def cache(expiration=60):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            key = hashlib.md5(json.dumps(args + tuple(kwargs.items())).encode()).hexdigest()
            cached_result = redis_client.get(key)
